}
*{box-sizing:border-box}
html{font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:var(--bg);color:var(--text)}
body{margin:0}button,input,select,textarea{font:inherit}.shell{min-height:100vh;padding:24px}.module{max-width:1620px;margin:auto}
.breadcrumb{display:flex;align-items:center;gap:7px;color:var(--muted);font-size:11px;margin-bottom:10px}.breadcrumb b{color:var(--text)}
.page-head{display:flex;justify-content:space-between;align-items:flex-start;gap:20px;margin-bottom:14px}.page-head h1{font-size:25px;margin:0 0 5px;letter-spacing:-.025em}.page-head p{font-size:12px;color:var(--muted);margin:0;line-height:1.5}
.head-actions{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.btn{height:36px;border:1px solid var(--line);background:#fff;color:var(--text);border-radius:9px;padding:0 12px;font-size:11px;font-weight:750;display:inline-flex;align-items:center;justify-content:center;gap:7px;cursor:pointer;transition:.15s;white-space:nowrap}
.btn:hover{border-color:#bdc8d3;box-shadow:0 5px 15px rgba(31,45,61,.07)}.btn.primary{background:var(--primary);border-color:var(--primary);color:#fff}.btn.primary:hover{background:var(--primary2)}
.btn.danger{color:var(--red);background:var(--red-soft);border-color:#f1c8ce}.btn.sm{height:29px;padding:0 8px;font-size:10px;border-radius:7px}.btn.icon{width:29px;padding:0}.btn:disabled{opacity:.42;cursor:not-allowed;box-shadow:none}
.userbox{display:flex;align-items:center;gap:7px;padding:4px 8px;border:1px solid var(--line);background:#fff;border-radius:9px}.userbox span{font-size:9px;color:var(--muted)}.userbox select{border:0;background:transparent;outline:0;font-size:10px;font-weight:750;max-width:180px}
.context{display:flex;align-items:center;gap:10px;padding:11px 13px;border:1px solid #cfe4e9;background:linear-gradient(120deg,#f0f9fb,#fbfdfe);border-radius:11px;margin-bottom:10px}
.context-icon{width:34px;height:34px;border-radius:9px;background:var(--primary-soft);color:var(--primary);display:grid;place-items:center;font-weight:900}.context strong{font-size:11px;display:block}.context span{font-size:9px;color:#5d7480}.context .push{margin-left:auto;display:flex;gap:7px}
.stats{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:9px;margin-bottom:11px}.stat{background:#fff;border:1px solid var(--line);border-radius:11px;padding:11px 13px;display:flex;align-items:center;gap:10px}
.stat-icon{width:33px;height:33px;border-radius:9px;background:var(--primary-soft);color:var(--primary);display:grid;place-items:center;font-weight:900}.stat strong{display:block;font-size:17px}.stat span{font-size:9px;color:var(--muted)}
.panel{background:#fff;border:1px solid var(--line);border-radius:var(--radius);overflow:hidden;box-shadow:0 4px 18px rgba(31,45,61,.035)}
.filters{display:flex;align-items:center;gap:7px;flex-wrap:wrap;padding:12px 13px;background:#fbfcfd;border-bottom:1px solid var(--line)}
.inline{position:relative}.inline input,.inline select{height:35px;border:1px solid var(--line);background:#fff;border-radius:8px;padding:0 9px;font-size:10px;color:var(--text);outline:0}
.inline input:focus,.inline select:focus{border-color:#69a9bc;box-shadow:0 0 0 3px rgba(23,107,135,.08)}.search input{width:270px;padding-left:31px}.search:before{content:"⌕";position:absolute;left:10px;top:6px;font-size:16px;color:#8796a8}
.filter-meta{margin-left:auto;display:flex;align-items:center;gap:8px;font-size:9px;color:var(--muted)}.filter-chip{display:none;background:var(--primary-soft);color:var(--primary);font-weight:750;border-radius:99px;padding:5px 8px}
.bulk{display:none;align-items:center;gap:8px;padding:9px 13px;background:#eef8fa;border-bottom:1px solid #cde4ea;font-size:10px}.bulk.show{display:flex}.bulk strong{color:var(--primary)}.bulk .push{margin-left:auto}
.table-wrap{overflow:auto;max-height:calc(100vh - 328px)}table{width:100%;border-collapse:separate;border-spacing:0;min-width:1470px}.data th{position:sticky;top:0;z-index:4;text-align:left;padding:9px 10px;background:#f8fafc;border-bottom:1px solid var(--line);font-size:8.3px;letter-spacing:.065em;text-transform:uppercase;color:#748397;white-space:nowrap}
.data td{padding:9px 10px;border-bottom:1px solid var(--line2);font-size:10px;background:#fff;vertical-align:middle}.data tbody tr:hover td{background:#fbfdfe}.data tbody tr.selected td{background:#f2fafc}
.check{width:36px;text-align:center}.maincell{font-weight:750}.subcell{font-size:8.5px;color:var(--muted);margin-top:3px}.code{font-family:ui-monospace,SFMono-Regular,Menlo,monospace;background:#eef3f6;color:#314557;border-radius:6px;padding:4px 6px;font-size:9.5px}
.measure{display:grid;grid-template-columns:1fr 1fr;gap:4px;min-width:130px}.measure span{display:flex;align-items:center;justify-content:space-between;background:#f7f9fb;border:1px solid var(--line2);border-radius:6px;padding:5px 6px;font-size:9px}.measure b{font-size:10px}
.measure .bad{color:var(--red);background:var(--red-soft);border-color:#f1c8ce}.measure .missing{color:var(--amber);background:var(--amber-soft);border-color:#f0dfbb}
.badge{display:inline-flex;align-items:center;gap:5px;padding:5px 7px;border-radius:99px;font-size:8.5px;font-weight:800;white-space:nowrap}.badge:before{content:"";width:6px;height:6px;border-radius:50%;background:currentColor}
.badge.complete,.badge.yes{background:var(--green-soft);color:var(--green)}.badge.alert,.badge.no{background:var(--red-soft);color:var(--red)}.badge.incomplete{background:var(--amber-soft);color:var(--amber)}.badge.remedy{background:var(--violet-soft);color:var(--violet)}
.remedy{max-width:190px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:#5f6e7f}.row-actions{display:flex;gap:4px;white-space:nowrap}
.pagination{display:flex;align-items:center;justify-content:space-between;padding:11px 13px;background:#fbfcfd;border-top:1px solid var(--line);font-size:9px;color:var(--muted)}.page-left,.page-right{display:flex;align-items:center;gap:7px}.pagination select{border:1px solid var(--line);background:#fff;border-radius:7px;padding:4px 6px;font-size:9px}
.empty{text-align:center;padding:48px;color:var(--muted)}.empty strong{display:block;color:var(--text);margin-bottom:5px}.empty .ico{font-size:31px;margin-bottom:8px}
.drawer-bg{position:fixed;inset:0;background:rgba(13,27,36,.32);z-index:60;display:none}.drawer-bg.show{display:block}.drawer{position:absolute;right:0;top:0;bottom:0;width:min(560px,100%);background:#fff;box-shadow:-18px 0 55px rgba(17,30,40,.2);display:flex;flex-direction:column}
.drawer-head{padding:18px;border-bottom:1px solid var(--line);display:flex;justify-content:space-between;align-items:flex-start}.drawer-head h2{font-size:16px;margin:0 0 4px}.drawer-head p{font-size:9px;color:var(--muted);margin:0}.close{width:29px;height:29px;border:0;background:#f0f3f6;border-radius:8px;cursor:pointer}
.drawer-body{padding:18px;overflow:auto}.drawer-foot{margin-top:auto;border-top:1px solid var(--line);padding:13px 18px;display:flex;justify-content:flex-end;gap:8px}
.detail-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px}.detail{background:#f8fafc;border:1px solid var(--line);border-radius:10px;padding:10px}.detail.full{grid-column:1/-1}.detail label{display:block;font-size:8px;text-transform:uppercase;letter-spacing:.07em;color:var(--muted);margin-bottom:5px}.detail strong{font-size:11px;line-height:1.5}
.reading-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}.reading{border:1px solid var(--line);border-radius:9px;padding:10px}.reading b{font-size:16px;display:block}.reading span{font-size:8.5px;color:var(--muted)}
.timeline{border-left:2px solid #e4e9ee;margin-left:6px;padding-left:16px;display:grid;gap:14px}.timeline-item{position:relative;font-size:9px;color:var(--muted)}.timeline-item:before{content:"";position:absolute;left:-22px;top:2px;width:8px;height:8px;border-radius:50%;background:var(--primary);box-shadow:0 0 0 4px var(--primary-soft)}.timeline-item strong{display:block;color:var(--text);margin-bottom:3px}
.modal-bg{position:fixed;inset:0;background:rgba(12,25,34,.42);backdrop-filter:blur(3px);z-index:80;display:none;align-items:center;justify-content:center;padding:18px}.modal-bg.show{display:flex}.modal{width:min(680px,100%);max-height:92vh;background:#fff;border-radius:16px;overflow:auto;box-shadow:var(--shadow)}.modal.wide{width:min(1040px,100%)}
.modal-head{padding:16px 18px;border-bottom:1px solid var(--line);display:flex;justify-content:space-between;align-items:flex-start}.modal-head h2{font-size:15px;margin:0 0 4px}.modal-head p{font-size:9px;color:var(--muted);margin:0}.modal-body{padding:18px}.modal-foot{padding:13px 18px;border-top:1px solid var(--line);display:flex;justify-content:flex-end;gap:8px}
.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.field{display:grid;gap:5px}.field.full{grid-column:1/-1}.field label{font-size:9px;font-weight:750;color:#425266}.field input,.field select,.field textarea{border:1px solid var(--line);border-radius:9px;padding:9px 10px;font-size:10px;outline:0;background:#fff}.field textarea{min-height:82px;resize:vertical}.field input:focus,.field select:focus,.field textarea:focus{border-color:#69a9bc;box-shadow:0 0 0 3px rgba(23,107,135,.08)}.help{font-size:8.5px;color:var(--muted)}
.measure-group{display:grid;grid-template-columns:110px 1fr 1fr;gap:9px;align-items:end;padding:11px;border:1px solid var(--line);border-radius:10px;background:#f8fafc}.measure-label strong{font-size:10px;display:block}.measure-label span{font-size:8px;color:var(--muted)}
.settings-note{padding:10px 12px;border:1px solid #efdfba;background:var(--amber-soft);color:#76511c;border-radius:9px;font-size:9px;line-height:1.5;margin-bottom:12px}
.month-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:7px}.day-card{border:1px solid var(--line);border-radius:9px;padding:8px;background:#fff;min-height:92px}.day-card.off{opacity:.45}.day-card strong{font-size:10px}.day-card span{display:block;font-size:8px;color:var(--muted);margin-top:4px}.day-card input{width:100%;border:1px solid var(--line);border-radius:6px;padding:5px;margin-top:5px;font-size:9px}
.toast-wrap{position:fixed;right:20px;bottom:20px;z-index:120;display:grid;gap:7px}.toast{background:#172d38;color:#fff;padding:10px 13px;border-radius:9px;font-size:10px;box-shadow:var(--shadow);animation:tin .18s ease}.toast.error{background:#8d303a}@keyframes tin{from{opacity:0;transform:translateY(7px)}}
@media(max-width:1050px){.stats{grid-template-columns:repeat(2,1fr)}.page-head{flex-direction:column}.filter-meta{margin-left:0}.userbox{display:none}.table-wrap{max-height:none}}
@media(max-width:620px){.shell{padding:14px}.stats{grid-template-columns:1fr}.search,.search input,.inline{width:100%}.inline input,.inline select{width:100%}.form-grid{grid-template-columns:1fr}.field.full,.detail.full{grid-column:auto}.detail-grid{grid-template-columns:1fr}.measure-group{grid-template-columns:1fr}.context{align-items:flex-start}.context .push{flex-direction:column}.month-grid{grid-template-columns:1fr 1fr}}
</style>
