const KEY="lab-environment-monitor-module-v1";
let state=null;
let ui={page:1,size:20,selected:new Set(),filters:{search:"",from:"",to:"",inspector:"",status:"",cleaning:""}};

function clone(v){return JSON.parse(JSON.stringify(v))}
async function load(){const r=await fetch(window.QMS_ENV.state,{credentials:'same-origin'});if(!r.ok)throw new Error('Không tải được dữ liệu');return await r.json()}
function save(message){fetch(window.QMS_ENV.save,{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':window.QMS_ENV.csrf},body:JSON.stringify(state)}).then(r=>{if(!r.ok)toast('Lưu thất bại','error')}).catch(()=>toast('Lưu thất bại','error'));if(message)toast(message)}
function esc(v){return String(v??"").replace(/[&<>"']/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[m]))}
function dateVi(v){return v?new Date(v+"T00:00:00").toLocaleDateString("vi-VN"):"—"}
function dateTimeVi(v){return v?new Date(v).toLocaleString("vi-VN"):"—"}
function today(){return new Date().toISOString().slice(0,10)}
function user(id){return state.users.find(x=>x.id===id)}
function currentUser(){return user(state.currentUserId)||state.users[0]}
function valueText(v,suffix=""){return v===null||v===undefined||v===""?"—":`${Number(v).toLocaleString("vi-VN",{maximumFractionDigits:1})}${suffix}`}
function toast(message,type=""){const el=document.createElement("div");el.className="toast "+type;el.textContent=message;document.getElementById("toastWrap").appendChild(el);setTimeout(()=>el.remove(),2900)}
function addHistory(record,action,detail){record.history=record.history||[];record.history.unshift({time:new Date().toISOString(),userId:state.currentUserId,action,detail});record.history=record.history.slice(0,20)}

function readingOutside(value,min,max){return value!==null&&value!==undefined&&(Number(value)<Number(min)||Number(value)>Number(max))}
function recordStatus(record){
 const s=state.settings;
 const values=[record.temperature1,record.temperature2,record.humidity1,record.humidity2];
 const missing=values.some(v=>v===null||v===undefined||v==="");
 const outside=readingOutside(record.temperature1,s.temperatureMin,s.temperatureMax)||readingOutside(record.temperature2,s.temperatureMin,s.temperatureMax)||readingOutside(record.humidity1,s.humidityMin,s.humidityMax)||readingOutside(record.humidity2,s.humidityMin,s.humidityMax);
 if(outside)return "alert";
 if(record.remedy&&record.remedy.trim())return "remedy";
 if(missing||record.cleaning!=="yes")return "incomplete";
 return "complete"
}
const STATUS={
 complete:["Đầy đủ, trong ngưỡng","complete"],
 incomplete:["Thiếu dữ liệu","incomplete"],
 alert:["Vượt ngưỡng","alert"],
 remedy:["Có khắc phục","remedy"]
};
function statusBadge(status){const x=STATUS[status]||STATUS.incomplete;return `<span class="badge ${x[1]}">${x[0]}</span>`}
function cleaningBadge(value){return value==="yes"?`<span class="badge yes">Đã vệ sinh</span>`:`<span class="badge no">Chưa vệ sinh</span>`}

function init(){
 document.getElementById("contextTitle").textContent=`${state.metadata.deviceName} · ${state.metadata.location}`;
 document.getElementById("contextSub").textContent=`Seri: ${state.metadata.serial} · Người xem xét: ${state.metadata.reviewer||"Chưa cập nhật"} · Đã loại ${state.importInfo.duplicatesRemoved} dòng trùng khi nhập`;
 const current=document.getElementById("currentUser");
 current.innerHTML=state.users.map(u=>`<option value="${u.id}" ${u.id===state.currentUserId?"selected":""}>${esc(u.name)}</option>`).join("");
 current.onchange=()=>{state.currentUserId=current.value;save();render()};
 document.getElementById("fInspector").innerHTML=`<option value="">Tất cả người kiểm tra</option>`+state.users.filter(u=>u.id!=="u-admin").map(u=>`<option value="${u.id}">${esc(u.name)}</option>`).join("");
 ["fSearch","fFrom","fTo","fInspector","fStatus","fCleaning"].forEach(id=>{
   document.getElementById(id).addEventListener(id==="fSearch"?"input":"change",readFilters)
 });
 document.getElementById("pageSize").onchange=e=>{ui.size=Number(e.target.value);ui.page=1;render()};
 document.getElementById("prev").onclick=()=>{ui.page--;render();scrollTopTable()};
 document.getElementById("next").onclick=()=>{ui.page++;render();scrollTopTable()};
 document.getElementById("checkAll").onchange=e=>{pageRows().forEach(r=>e.target.checked?ui.selected.add(r.id):ui.selected.delete(r.id));render()};
 render()
}
function readFilters(){
 ui.filters={
  search:document.getElementById("fSearch").value.trim(),
  from:document.getElementById("fFrom").value,
  to:document.getElementById("fTo").value,
  inspector:document.getElementById("fInspector").value,
  status:document.getElementById("fStatus").value,
  cleaning:document.getElementById("fCleaning").value
 };ui.page=1;render()
}
function clearFilters(){
 ["fSearch","fFrom","fTo","fInspector","fStatus","fCleaning"].forEach(id=>document.getElementById(id).value="");
 ui.filters={search:"",from:"",to:"",inspector:"",status:"",cleaning:""};ui.page=1;render()
}
function filtered(){
 const f=ui.filters,q=f.search.toLowerCase();
 return state.records.filter(r=>{
  const text=[user(r.inspectorId)?.name,r.remedy,state.metadata.location,state.metadata.deviceName].join(" ").toLowerCase();
  return(!q||text.includes(q))&&(!f.from||r.date>=f.from)&&(!f.to||r.date<=f.to)&&(!f.inspector||r.inspectorId===f.inspector)&&(!f.status||recordStatus(r)===f.status)&&(!f.cleaning||r.cleaning===f.cleaning)
 }).sort((a,b)=>(b.date+b.updatedAt).localeCompare(a.date+a.updatedAt))
}
function pageRows(){
 const rows=filtered(),pages=Math.max(1,Math.ceil(rows.length/ui.size));ui.page=Math.min(Math.max(ui.page,1),pages);
 return rows.slice((ui.page-1)*ui.size,ui.page*ui.size)
}
function average(values){const valid=values.filter(v=>v!==null&&v!==undefined&&!Number.isNaN(Number(v))).map(Number);return valid.length?valid.reduce((a,b)=>a+b,0)/valid.length:null}
function renderStats(rows){
 const avgTemp=average(rows.flatMap(r=>[r.temperature1,r.temperature2]));
 const avgHumidity=average(rows.flatMap(r=>[r.humidity1,r.humidity2]));
 const alerts=rows.filter(r=>recordStatus(r)==="alert").length;
 const incomplete=rows.filter(r=>recordStatus(r)==="incomplete").length;
 document.getElementById("stats").innerHTML=[
  ["≣",rows.length,"Bản ghi đang hiển thị"],
  ["℃",avgTemp===null?"—":avgTemp.toLocaleString("vi-VN",{maximumFractionDigits:1})+"°C","Nhiệt độ trung bình"],
  ["%",avgHumidity===null?"—":avgHumidity.toLocaleString("vi-VN",{maximumFractionDigits:1})+"%","Độ ẩm trung bình"],
  ["!",alerts,"Bản ghi vượt ngưỡng"],
  ["…",incomplete,"Bản ghi chưa đầy đủ"]
 ].map(x=>`<article class="stat"><div class="stat-icon">${x[0]}</div><div><strong>${x[1]}</strong><span>${x[2]}</span></div></article>`).join("")
}
function render(){
 const rows=filtered(),paged=pageRows(),pages=Math.max(1,Math.ceil(rows.length/ui.size));
 renderStats(rows);
 document.getElementById("countText").textContent=`${rows.length} bản ghi`;
 const active=Object.values(ui.filters).filter(Boolean).length,chip=document.getElementById("filterChip");chip.style.display=active?"inline-flex":"none";chip.textContent=`${active} điều kiện lọc`;
 document.getElementById("tbody").innerHTML=paged.length?paged.map(rowHtml).join(""):`<tr><td colspan="10"><div class="empty"><div class="ico">⌕</div><strong>Không tìm thấy dữ liệu</strong><span>Thử thay đổi bộ lọc hoặc thêm bản ghi mới.</span></div></td></tr>`;
 const start=rows.length?(ui.page-1)*ui.size+1:0,end=Math.min(ui.page*ui.size,rows.length);
 document.getElementById("rangeText").textContent=`${start}–${end} / ${rows.length} bản ghi`;document.getElementById("pageText").textContent=`Trang ${ui.page}/${pages}`;
 document.getElementById("prev").disabled=ui.page<=1;document.getElementById("next").disabled=ui.page>=pages;document.getElementById("pageSize").value=String(ui.size);
 document.getElementById("checkAll").checked=!!(paged.length&&paged.every(r=>ui.selected.has(r.id)));updateBulk()
}
function readingCell(v,label,min,max){
 const cls=v===null||v===undefined?"missing":readingOutside(v,min,max)?"bad":"";
 return `<span class="${cls}"><small>${label}</small><b>${valueText(v)}</b></span>`
}
function rowHtml(r){
 const s=state.settings,selected=ui.selected.has(r.id),status=recordStatus(r);
 return `<tr class="${selected?"selected":""}">
  <td class="check"><input type="checkbox" ${selected?"checked":""} onchange="toggleSelect('${r.id}',this.checked)"></td>
  <td><div class="maincell">${dateVi(r.date)}</div><div class="subcell">${esc(r.id)}</div></td>
  <td><div class="maincell">${esc(user(r.inspectorId)?.name||"—")}</div><div class="subcell">${esc(state.metadata.location)}</div></td>
  <td><div class="measure">${readingCell(r.temperature1,s.measurementTime1,s.temperatureMin,s.temperatureMax)}${readingCell(r.temperature2,s.measurementTime2,s.temperatureMin,s.temperatureMax)}</div><div class="subcell">Ngưỡng ${s.temperatureMin}–${s.temperatureMax}°C</div></td>
  <td><div class="measure">${readingCell(r.humidity1,s.measurementTime1,s.humidityMin,s.humidityMax)}${readingCell(r.humidity2,s.measurementTime2,s.humidityMin,s.humidityMax)}</div><div class="subcell">Ngưỡng ${s.humidityMin}–${s.humidityMax}%</div></td>
  <td>${cleaningBadge(r.cleaning)}</td>
  <td><div class="remedy" title="${esc(r.remedy)}">${esc(r.remedy||"—")}</div></td>
  <td>${statusBadge(status)}</td>
  <td><div class="maincell">${dateVi(r.updatedAt.slice(0,10))}</div><div class="subcell">${new Date(r.updatedAt).toLocaleTimeString("vi-VN",{hour:"2-digit",minute:"2-digit"})}</div></td>
  <td><div class="row-actions"><button class="btn sm icon" title="Xem chi tiết" onclick="openDetail('${r.id}')">◉</button><button class="btn sm icon" title="Chỉnh sửa" onclick="openForm('${r.id}')">✎</button><button class="btn sm icon" title="Nhân bản" onclick="duplicateOne('${r.id}')">⧉</button><button class="btn sm icon danger" title="Xóa" onclick="deleteOne('${r.id}')">×</button></div></td>
 </tr>`
}
function toggleSelect(id,on){on?ui.selected.add(id):ui.selected.delete(id);render()}
function clearSelection(){ui.selected.clear();render()}
function updateBulk(){const n=ui.selected.size;document.getElementById("bulkbar").classList.toggle("show",n>0);document.getElementById("selectedText").textContent=`${n} bản ghi đã chọn`}
function scrollTopTable(){document.querySelector(".table-wrap").scrollTo({top:0,behavior:"smooth"})}

function openDetail(id){
 const r=state.records.find(x=>x.id===id);if(!r)return;const s=state.settings;
 document.getElementById("drawerTitle").textContent=`Theo dõi ngày ${dateVi(r.date)}`;
 document.getElementById("drawerSub").textContent=`${r.id} · Phiên bản ${r.version||1} · ${state.metadata.location}`;
 document.getElementById("drawerBody").innerHTML=`
  <div class="detail-grid">
   <div class="detail"><label>Người kiểm tra</label><strong>${esc(user(r.inspectorId)?.name||"—")}</strong></div>
   <div class="detail"><label>Trạng thái</label>${statusBadge(recordStatus(r))}</div>
   <div class="detail full"><label>Thiết bị và vị trí</label><strong>${esc(state.metadata.deviceName)} · Seri ${esc(state.metadata.serial)}</strong><div class="subcell">${esc(state.metadata.location)}</div></div>
   <div class="detail full"><label>Nhiệt độ</label><div class="reading-grid"><div class="reading"><b>${valueText(r.temperature1,"°C")}</b><span>Lần 1 · ${s.measurementTime1}</span></div><div class="reading"><b>${valueText(r.temperature2,"°C")}</b><span>Lần 2 · ${s.measurementTime2}</span></div></div></div>
   <div class="detail full"><label>Độ ẩm</label><div class="reading-grid"><div class="reading"><b>${valueText(r.humidity1,"%")}</b><span>Lần 1 · ${s.measurementTime1}</span></div><div class="reading"><b>${valueText(r.humidity2,"%")}</b><span>Lần 2 · ${s.measurementTime2}</span></div></div></div>
   <div class="detail"><label>Vệ sinh</label>${cleaningBadge(r.cleaning)}</div>
   <div class="detail"><label>Cập nhật gần nhất</label><strong>${dateTimeVi(r.updatedAt)}</strong></div>
   <div class="detail full"><label>Biện pháp khắc phục</label><strong>${esc(r.remedy||"Không có biện pháp khắc phục")}</strong></div>
  </div>
  <h3 style="font-size:11px;margin:0 0 12px">Lịch sử bản ghi</h3>
  <div class="timeline">${(r.history||[]).length?(r.history||[]).map(h=>`<div class="timeline-item"><strong>${esc(h.action)} · ${esc(user(h.userId)?.name||"Hệ thống")}</strong><span>${dateTimeVi(h.time)} — ${esc(h.detail)}</span></div>`).join(""):`<div class="timeline-item"><strong>Nhập dữ liệu ban đầu</strong><span>${dateTimeVi(r.createdAt)} — Chuẩn hóa từ biểu mẫu Excel.</span></div>`}</div>`;
 document.getElementById("drawerFoot").innerHTML=`<button class="btn" onclick="duplicateOne('${id}')">⧉ Nhân bản</button><button class="btn primary" onclick="closeDrawer();openForm('${id}')">✎ Chỉnh sửa</button>`;
 document.getElementById("drawerBg").classList.add("show")
}
function closeDrawer(){document.getElementById("drawerBg").classList.remove("show")}
document.getElementById("drawerBg").addEventListener("click",e=>{if(e.target.id==="drawerBg")closeDrawer()});

function openForm(id="",prefill={}){
 const old=id?state.records.find(x=>x.id===id):null;
 const r=old||{date:prefill.date||today(),inspectorId:prefill.inspectorId||state.currentUserId,temperature1:prefill.temperature1??null,temperature2:prefill.temperature2??null,humidity1:prefill.humidity1??null,humidity2:prefill.humidity2??null,cleaning:prefill.cleaning||"yes",remedy:prefill.remedy||""};
 const s=state.settings;
 openModal(old?"Cập nhật bản ghi":"Thêm bản ghi môi trường","Hai lần đo được lưu trong cùng một bản ghi ngày để tránh nhập thành nhiều dòng rời.",`
  <form class="form-grid" id="recordForm">
   <div class="field"><label>Ngày kiểm tra *</label><input name="date" type="date" required value="${r.date}"></div>
   <div class="field"><label>Người kiểm tra *</label><select name="inspectorId">${state.users.filter(u=>u.id!=="u-admin").map(u=>`<option value="${u.id}" ${u.id===r.inspectorId?"selected":""}>${esc(u.name)}</option>`).join("")}</select></div>

   <div class="field full"><label>Thông số lần đo thứ nhất</label><div class="measure-group">
    <div class="measure-label"><strong>${s.measurementTime1}</strong><span>Thời điểm cấu hình</span></div>
    <div class="field"><label>Nhiệt độ (°C)</label><input name="temperature1" type="number" step=".1" value="${r.temperature1??""}" placeholder="${s.temperatureMin}–${s.temperatureMax}"></div>
    <div class="field"><label>Độ ẩm (%)</label><input name="humidity1" type="number" step=".1" value="${r.humidity1??""}" placeholder="${s.humidityMin}–${s.humidityMax}"></div>
   </div></div>

   <div class="field full"><label>Thông số lần đo thứ hai</label><div class="measure-group">
    <div class="measure-label"><strong>${s.measurementTime2}</strong><span>Thời điểm cấu hình</span></div>
    <div class="field"><label>Nhiệt độ (°C)</label><input name="temperature2" type="number" step=".1" value="${r.temperature2??""}" placeholder="${s.temperatureMin}–${s.temperatureMax}"></div>
    <div class="field"><label>Độ ẩm (%)</label><input name="humidity2" type="number" step=".1" value="${r.humidity2??""}" placeholder="${s.humidityMin}–${s.humidityMax}"></div>
   </div></div>

   <div class="field"><label>Vệ sinh phòng *</label><select name="cleaning"><option value="yes" ${r.cleaning==="yes"?"selected":""}>Đã vệ sinh</option><option value="no" ${r.cleaning==="no"?"selected":""}>Chưa vệ sinh</option></select></div>
   <div class="field full"><label>Biện pháp khắc phục</label><textarea name="remedy" placeholder="Nhập khi nhiệt độ/độ ẩm vượt ngưỡng hoặc chưa hoàn thành vệ sinh...">${esc(r.remedy)}</textarea><span class="help">Hệ thống tự đánh dấu vượt ngưỡng dựa trên phần Cấu hình ngưỡng.</span></div>
  </form>`,old?"Lưu thay đổi":"Thêm bản ghi",()=>{
   const fd=new FormData(document.getElementById("recordForm")),x=Object.fromEntries(fd.entries());
   if(!x.date||!x.inspectorId){toast("Vui lòng chọn ngày và người kiểm tra","error");return}
   ["temperature1","temperature2","humidity1","humidity2"].forEach(k=>x[k]=x[k]===""?null:Number(x[k]));
   const duplicate=state.records.find(item=>item.date===x.date&&item.id!==old?.id);
   if(duplicate&&!confirm(`Ngày ${dateVi(x.date)} đã có bản ghi. Vẫn tiếp tục lưu thêm?`))return;
   if(old){Object.assign(old,x,{updatedAt:new Date().toISOString(),version:(old.version||1)+1});addHistory(old,"UPDATE","Cập nhật thông số môi trường.")}
   else{const n={id:"env-"+Date.now(),...x,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),version:1,history:[]};addHistory(n,"CREATE","Tạo bản ghi mới.");state.records.unshift(n)}
   save(old?"Đã cập nhật bản ghi":"Đã thêm bản ghi");closeModal();render();if(!old)QMSFlow.done()
 })
}
function openLatestCopy(){
 const latest=[...state.records].sort((a,b)=>b.date.localeCompare(a.date))[0];
 if(!latest){openForm();return}
 openForm("",{...clone(latest),date:today(),inspectorId:state.currentUserId})
}
function duplicateOne(id){
 const r=state.records.find(x=>x.id===id);if(!r)return;openForm("",{...clone(r),date:today(),inspectorId:state.currentUserId});closeDrawer()
}
function duplicateSelected(){
 const rows=state.records.filter(r=>ui.selected.has(r.id));if(!rows.length)return;
 const now=Date.now();rows.forEach((r,i)=>{const n={...clone(r),id:`env-${now}-${i}`,date:today(),inspectorId:state.currentUserId,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),version:1,history:[]};addHistory(n,"CREATE","Nhân bản hàng loạt từ "+r.id);state.records.unshift(n)});
 ui.selected.clear();save(`Đã nhân bản ${rows.length} bản ghi`);render()
}
function deleteOne(id){
 const r=state.records.find(x=>x.id===id);if(!r)return;
 if(confirm(`Xóa bản ghi ngày ${dateVi(r.date)}?`)){state.records=state.records.filter(x=>x.id!==id);ui.selected.delete(id);save("Đã xóa bản ghi");closeDrawer();render()}
}
function deleteSelected(){
 const n=ui.selected.size;if(!n)return;
 if(confirm(`Xóa ${n} bản ghi đã chọn?`)){state.records=state.records.filter(r=>!ui.selected.has(r.id));ui.selected.clear();save(`Đã xóa ${n} bản ghi`);render()}
}

function openSettings(){
 const s=state.settings;
 openModal("Cấu hình ngưỡng và thời điểm đo","Các giá trị dưới đây là cấu hình vận hành của module, cần điều chỉnh theo quy trình áp dụng thực tế.",`
  <div class="settings-note">Ngưỡng hiện tại chỉ là dữ liệu cấu hình mẫu của giao diện, không thay thế quy trình hoặc tiêu chuẩn chuyên môn của đơn vị.</div>
  <form class="form-grid" id="settingsForm">
   <div class="field"><label>Nhiệt độ tối thiểu (°C)</label><input name="temperatureMin" type="number" step=".1" value="${s.temperatureMin}"></div>
   <div class="field"><label>Nhiệt độ tối đa (°C)</label><input name="temperatureMax" type="number" step=".1" value="${s.temperatureMax}"></div>
   <div class="field"><label>Độ ẩm tối thiểu (%)</label><input name="humidityMin" type="number" step=".1" value="${s.humidityMin}"></div>
   <div class="field"><label>Độ ẩm tối đa (%)</label><input name="humidityMax" type="number" step=".1" value="${s.humidityMax}"></div>
   <div class="field"><label>Thời điểm đo lần 1</label><input name="measurementTime1" type="time" value="${s.measurementTime1}"></div>
   <div class="field"><label>Thời điểm đo lần 2</label><input name="measurementTime2" type="time" value="${s.measurementTime2}"></div>
  </form>`,`Lưu cấu hình`,()=>{
   const x=Object.fromEntries(new FormData(document.getElementById("settingsForm")).entries());
   ["temperatureMin","temperatureMax","humidityMin","humidityMax"].forEach(k=>x[k]=Number(x[k]));
   if(x.temperatureMin>=x.temperatureMax||x.humidityMin>=x.humidityMax){toast("Ngưỡng tối thiểu phải nhỏ hơn ngưỡng tối đa","error");return}
   state.settings=x;save("Đã lưu cấu hình ngưỡng");closeModal();render()
 })
}

function openMonthEntry(){
 const now=new Date(),year=now.getFullYear(),month=now.getMonth()+1;
 openModal("Nhập nhanh theo tháng","Tạo hoặc cập nhật nhiều ngày trong tháng cho cùng một người kiểm tra.",`
  <div class="form-grid" style="margin-bottom:12px">
   <div class="field"><label>Tháng</label><input id="monthInput" type="month" value="${year}-${String(month).padStart(2,"0")}" onchange="renderMonthGrid()"></div>
   <div class="field"><label>Người kiểm tra</label><select id="monthInspector">${state.users.filter(u=>u.id!=="u-admin").map(u=>`<option value="${u.id}">${esc(u.name)}</option>`).join("")}</select></div>
  </div>
  <div class="settings-note">Nhập nhanh này phù hợp khi bổ sung dữ liệu từ sổ giấy. Mỗi ô gồm nhiệt độ và độ ẩm; dữ liệu lần 1 và lần 2 sẽ được điền giống nhau, sau đó có thể chỉnh lại từng ngày.</div>
  <div class="qp-host"></div><div id="monthGrid" class="month-grid"></div>`,`Lưu các ngày đã nhập`,saveMonthEntry,true);
 QMSPreset.attach("month",{host:"#modalBody .qp-host",collect:collectMonthPreset,apply:applyMonthPreset});
 setTimeout(renderMonthGrid,0)
}
function renderMonthGrid(){
 const val=document.getElementById("monthInput")?.value;if(!val)return;
 const [year,month]=val.split("-").map(Number),days=new Date(year,month,0).getDate(),container=document.getElementById("monthGrid");
 container.innerHTML=Array.from({length:days},(_,i)=>{const day=i+1,date=`${year}-${String(month).padStart(2,"0")}-${String(day).padStart(2,"0")}`;return `<div class="day-card" data-date="${date}"><strong>Ngày ${day}</strong><span>Nhiệt độ (°C)</span><input class="m-temp" type="number" step=".1" placeholder="—"><span>Độ ẩm (%)</span><input class="m-hum" type="number" step=".1" placeholder="—"></div>`}).join("")
}
function saveMonthEntry(){
 const inspectorId=document.getElementById("monthInspector").value,cards=[...document.querySelectorAll(".day-card")],now=Date.now();let created=0,updated=0;
 cards.forEach((card,i)=>{
  const temp=card.querySelector(".m-temp").value,hum=card.querySelector(".m-hum").value;if(temp===""&&hum==="")return;
  const date=card.dataset.date,existing=state.records.find(r=>r.date===date);
  const values={inspectorId,temperature1:temp===""?null:Number(temp),temperature2:temp===""?null:Number(temp),humidity1:hum===""?null:Number(hum),humidity2:hum===""?null:Number(hum),cleaning:"yes",remedy:""};
  if(existing){Object.assign(existing,values,{updatedAt:new Date().toISOString(),version:(existing.version||1)+1});addHistory(existing,"UPDATE","Cập nhật bằng nhập nhanh theo tháng.");updated++}
  else{const n={id:`env-${now}-${i}`,date,...values,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),version:1,history:[]};addHistory(n,"CREATE","Tạo bằng nhập nhanh theo tháng.");state.records.unshift(n);created++}
 });
 if(!created&&!updated){toast("Chưa nhập dữ liệu ngày nào","error");return}
 save(`Đã lưu: ${created} mới, ${updated} cập nhật`);closeModal();render();QMSFlow.done()
}

function openModal(title,sub,body,saveLabel,handler,wide=false){
 document.getElementById("modalTitle").textContent=title;document.getElementById("modalSub").textContent=sub||"";document.getElementById("modalBody").innerHTML=body;
 document.getElementById("modalFoot").innerHTML=`<button class="btn" onclick="closeModal()">Hủy</button>${saveLabel?`<button class="btn primary" id="modalSave">${saveLabel}</button>`:""}`;
 document.getElementById("modalBox").classList.toggle("wide",wide);document.getElementById("modalBg").classList.add("show");if(saveLabel)document.getElementById("modalSave").onclick=handler
}
function closeModal(){document.getElementById("modalBg").classList.remove("show")}
document.getElementById("modalBg").addEventListener("click",e=>{if(e.target.id==="modalBg")closeModal()});

function csvCell(v){return `"${String(v??"").replace(/"/g,'""')}"`}
function exportCsv(){
 const s=state.settings;
 const rows=[["Ngày","Người kiểm tra",`Nhiệt độ ${s.measurementTime1}`,`Nhiệt độ ${s.measurementTime2}`,`Độ ẩm ${s.measurementTime1}`,`Độ ẩm ${s.measurementTime2}`,"Vệ sinh","Biện pháp khắc phục","Trạng thái"],...filtered().map(r=>[r.date,user(r.inspectorId)?.name,r.temperature1,r.temperature2,r.humidity1,r.humidity2,r.cleaning==="yes"?"Có":"Không",r.remedy,STATUS[recordStatus(r)][0]])];
 const blob=new Blob(["\ufeff"+rows.map(row=>row.map(csvCell).join(",")).join("\n")],{type:"text/csv;charset=utf-8"});const a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download="theo-doi-nhiet-do-do-am-ve-sinh.csv";a.click();URL.revokeObjectURL(a.href);toast(`Đã xuất ${rows.length-1} bản ghi`)
}
window.addEventListener("storage",e=>{if(e.key===KEY&&e.newValue){try{state=JSON.parse(e.newValue);render();toast("Dữ liệu vừa được cập nhật từ tab khác")}catch(_){}}});
(async()=>{try{state=await load();await QMSPreset.init({url:window.QMS_ENV.preset,csrf:window.QMS_ENV.csrf});init();QMSFlow.init({url:window.QMS_ENV.flow,module:'env',openers:{daily:()=>openForm(),month:()=>openMonthEntry()}})}catch(e){document.body.insertAdjacentHTML('beforeend','<div class="toast error" style="position:fixed;left:20px;bottom:20px">'+e.message+'</div>')}})();

/* ==== mẫu mặc định cho nhập nhanh theo tháng ==== */
function collectMonthPreset(){return {inspector:document.getElementById("monthInspector").value}}
function applyMonthPreset(p){
 const sel=document.getElementById("monthInspector");
 if(p.inspector&&[...sel.options].some(o=>o.value===p.inspector))sel.value=p.inspector;
}
</script>
</body>
</html>